arguments.file_text:
@page "/apply"
@rendermode InteractiveServer
@using sv_4b830d8968bd408a8b8e4a470ddf03b1.Services
@inject IApplicationService ApplicationService

<PageTitle>Job Application</PageTitle>

<div class="apply-container">
    <h1>Job Application</h1>

    @* Step Indicator Bar *@
    <nav class="step-indicator" aria-label="Application steps">
        @for (int i = 0; i < StepNames.Length; i++)
        {
            var stepIndex = i;
            var status = GetStepStatus(stepIndex);
            <button class="step-item @status"
                    disabled="@(status == "future")"
                    @onclick="() => GoToStep(stepIndex)"
                    aria-current="@(stepIndex == currentStep ? "step" : null)">
                <span class="step-number">
                    @if (status == "completed")
                    {
                        <span class="checkmark">✓</span>
                    }
                    else
                    {
                        @(stepIndex + 1)
                    }
                </span>
                <span class="step-label">@StepNames[stepIndex]</span>
            </button>
        }
    </nav>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="error-banner" role="alert">@errorMessage</div>
    }

    @* Step Content *@
    <div class="step-content">
        @switch (currentStep)
        {
            case 0:
                @RenderPersonalInfo()
                break;
            case 1:
                @RenderWorkHistory()
                break;
            case 2:
                @RenderReferences()
                break;
            case 3:
                @RenderCoverLetter()
                break;
            case 4:
                @RenderReviewSubmit()
                break;
        }
    </div>
</div>

@* Step 1: Personal Info *@
@{ RenderFragment RenderPersonalInfo() => @<div class="form-step">
    <h2>Personal Information</h2>
    <div class="form-group">
        <label for="fullName">Full Name <span class="required">*</span></label>
        <input id="fullName" type="text" @bind="fullName" @bind:event="oninput" placeholder="Enter your full name" />
    </div>
    <div class="form-group">
        <label for="email">Email <span class="required">*</span></label>
        <input id="email" type="email" @bind="email" @bind:event="oninput" placeholder="Enter your email" />
        @if (!string.IsNullOrEmpty(emailError))
        {
            <span class="field-error">@emailError</span>
        }
    </div>
    <div class="form-group">
        <label for="phone">Phone <span class="required">*</span></label>
