@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
    private const int MaxCoverLetterLength = 2000;

    private int currentStep = 0;
    private int highestCompletedStep = -1;
    private string errorMessage = string.Empty;
    private string emailError = string.Empty;
    private bool isValidating = false;
    private bool isSubmitting = false;
    private bool isSubmitted = false;
    private int submittedId = 0;

    // Step 1: Personal Info
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2: Work History
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3: References
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4: Cover Letter
    private string coverLetter = string.Empty;

    private string GetStepStatus(int step)
    {
        if (step == currentStep) return "active";
        if (step <= highestCompletedStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step <= highestCompletedStep || step == currentStep)
        {
            currentStep = step;
            errorMessage = string.Empty;
        }
    }

    private void NextStep()
    {
        errorMessage = string.Empty;
        if (currentStep > highestCompletedStep)
            highestCompletedStep = currentStep;
        currentStep++;
    }

    private void PrevStep()
    {
        errorMessage = string.Empty;
        if (currentStep > 0) currentStep--;
    }

    // Step 1 validation
    private async Task NextFromPersonalInfo()
    {
        errorMessage = string.Empty;
        emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                errorMessage = "Email validation failed.";
                return;
            }
            NextStep();
        }
        finally
        {
            isValidating = false;
        }
    }

    // Step 2 validation
    private void NextFromWorkHistory()
    {
        errorMessage = string.Empty;
        foreach (var entry in workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == null)
            {
                errorMessage = "Please fill in company name, job title, and start date for all positions.";
                return;
            }
        }
        NextStep();
    }

    // Step 3 validation
    private void NextFromReferences()
    {
        errorMessage = string.Empty;
        foreach (var refEntry in references)
        {
            if (string.IsNullOrWhiteSpace(refEntry.Name) || string.IsNullOrWhiteSpace(refEntry.Relationship) ||
                string.IsNullOrWhiteSpace(refEntry.Email) || string.IsNullOrWhiteSpace(refEntry.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        NextStep();
    }

    // Work entry management
    private void AddWorkEntry() => workEntries.Add(new WorkEntryModel());

    private void RemoveWorkEntry(int index)
    {
        if (workEntries.Count > 1) workEntries.RemoveAt(index);
    }

    private void UpdateWorkEntry(int index, WorkEntryModel updated) => workEntries[index] = updated;

    private void UpdateWorkEntryStartDate(int index, string? value)
    {
        if (DateTime.TryParse(value, out var date))
            workEntries[index] = workEntries[index] with { StartDate = date };
    }

    private void UpdateWorkEntryEndDate(int index, string? value)
    {
        if (DateTime.TryParse(value, out var date))
            workEntries[index] = workEntries[index] with { EndDate = date };
        else
            workEntries[index] = workEntries[index] with { EndDate = null };
    }

    private void ToggleCurrentJob(int index, bool isCurrent)
    {
        workEntries[index] = workEntries[index] with { IsCurrent = isCurrent, EndDate = isCurrent ? null : workEntries[index].EndDate };
    }

    // Reference management
    private void AddReference()
    {
        if (references.Count < 3) references.Add(new ReferenceModel());
    }

    private void RemoveReference(int index)
    {
        if (references.Count > 2) references.RemoveAt(index);
    }

    private void UpdateReference(int index, ReferenceModel updated) => references[index] = updated;

    // Submission
    private async Task SubmitApplication()
    {
        isSubmitting = true;
        errorMessage = string.Empty;
        try
        {
            var application = new JobApplication(
                new PersonalInfo(fullName, email, phone, address),
                new WorkHistory(workEntries.Select(e => new WorkEntry(
                    e.Company, e.Title, e.StartDate ?? DateTime.MinValue, e.IsCurrent ? null : e.EndDate, e.Description
                )).ToList()),
                references.Select(r => new Reference(r.Name, r.Relationship, r.Email, r.Phone)).ToList(),
                coverLetter
            );

            submittedId = await ApplicationService.SubmitApplicationAsync(application);
            isSubmitted = true;
            if (currentStep > highestCompletedStep)
                highestCompletedStep = currentStep;
        }
        catch (Exception ex)
        {
            errorMessage = $"Submission failed: {ex.Message}. Please try again.";
        }
        finally
        {
            isSubmitting = false;
        }
    }

    // Models for form state
    private record WorkEntryModel
    {
        public string Company { get; init; } = string.Empty;
        public string Title { get; init; } = string.Empty;
        public DateTime? StartDate { get; init; }
        public DateTime? EndDate { get; init; }
        public bool IsCurrent { get; init; }
        public string Description { get; init; } = string.Empty;
    }

    private record ReferenceModel
    {
        public string Name { get; init; } = string.Empty;
        public string Relationship { get; init; } = string.Empty;
        public string Email { get; init; } = string.Empty;
        public string Phone { get; init; } = string.Empty;
    }
}

