@code {
    private static readonly string[] StepNames = { "Personal Info", "Work History", "References", "Cover Letter", "Review & Submit" };
    private const int MaxCoverLetterLength = 2000;

    private int currentStep = 0;
    private int highestCompletedStep = -1;
    private string errorMessage = string.Empty;
    private string emailError = string.Empty;
    private bool isValidating = false;
    private bool isSubmitting = false;
    private bool isSubmitted = false;
    private int submittedId = 0;

    // Step 1: Personal Info
    private string fullName = string.Empty;
    private string email = string.Empty;
    private string phone = string.Empty;
    private string address = string.Empty;

    // Step 2: Work History
    private List<WorkEntryModel> workEntries = new() { new WorkEntryModel() };

    // Step 3: References
    private List<ReferenceModel> references = new() { new ReferenceModel(), new ReferenceModel() };

    // Step 4: Cover Letter
    private string coverLetter = string.Empty;

    private string GetStepStatus(int step)
    {
        if (step == currentStep) return "active";
        if (step <= highestCompletedStep) return "completed";
        return "future";
    }

    private void GoToStep(int step)
    {
        if (step <= highestCompletedStep || step == currentStep)
        {
            currentStep = step;
            errorMessage = string.Empty;
        }
    }

    private void NextStep()
    {
        errorMessage = string.Empty;
        if (currentStep > highestCompletedStep)
            highestCompletedStep = currentStep;
        currentStep++;
    }

    private void PrevStep()
    {
        errorMessage = string.Empty;
        if (currentStep > 0) currentStep--;
    }

    // Step 1 validation
    private async Task NextFromPersonalInfo()
    {
        errorMessage = string.Empty;
        emailError = string.Empty;

        if (string.IsNullOrWhiteSpace(fullName) || string.IsNullOrWhiteSpace(email) ||
            string.IsNullOrWhiteSpace(phone) || string.IsNullOrWhiteSpace(address))
        {
            errorMessage = "Please fill in all required fields.";
            return;
        }

        isValidating = true;
        try
        {
            var isValid = await ApplicationService.ValidateEmailAsync(email);
            if (!isValid)
            {
                emailError = "Please enter a valid email address.";
                errorMessage = "Email validation failed.";
                return;
            }
            NextStep();
        }
        finally
        {
            isValidating = false;
        }
    }

    // Step 2 validation
    private void NextFromWorkHistory()
    {
        errorMessage = string.Empty;
        foreach (var entry in workEntries)
        {
            if (string.IsNullOrWhiteSpace(entry.Company) || string.IsNullOrWhiteSpace(entry.Title) || entry.StartDate == null)
            {
                errorMessage = "Please fill in company name, job title, and start date for all positions.";
                return;
            }
        }
        NextStep();
    }

    // Step 3 validation
    private void NextFromReferences()
    {
        errorMessage = string.Empty;
        foreach (var refEntry in references)
        {
            if (string.IsNullOrWhiteSpace(refEntry.Name) || string.IsNullOrWhiteSpace(refEntry.Relationship) ||
                string.IsNullOrWhiteSpace(refEntry.Email) || string.IsNullOrWhiteSpace(refEntry.Phone))
            {
                errorMessage = "Please fill in all fields for each reference.";
                return;
            }
        }
        NextStep();
    }

